 ctaglen = cinfo->taglen;
 tag_actions = cinfo->tag_actions;
 tag_actions_size = cinfo->tag_actions_size;
 tag_datas = cinfo->tag_datas;
 tag_datas_size = cinfo->tag_datas_size;
